const body = $input.first().json.body || $input.first().json;
const keywords = body.keywords;
const client = body.client;
if (!client || typeof client !== 'string' || !client.trim()) throw new Error('Missing: client');
if (!Array.isArray(keywords) || keywords.length === 0) throw new Error('Missing: keywords array');
const kws = [...new Set(keywords.map(k => String(k).trim()).filter(k => k))];
return [{ json: {
  client: client.trim(),
  client_name: body.client_name || client.trim(),
  job_name: body.job_name || ('SERP ' + new Date().toISOString().slice(0,10)),
  keywords: kws,
  lang: body.lang || 'cs',
  country: body.country || 'cz',
  num: parseInt(body.num || 10),
  keyword_count: kws.length
}}];

const jobId = $('Create Job').first().json.id;
const keywords = $('Validate').first().json.keywords;
const values = keywords.map(kw => `(${jobId}, '${kw.replace(/'/g, "''")}')`).join(',');
const sql = `INSERT INTO seo_kws.tasks (job_id, keyword) VALUES ${values} ON CONFLICT (job_id, keyword) DO NOTHING`;
return [{ json: {
  sql, job_id: jobId,
  task_count: keywords.length,
  client_id: $('Upsert Client').first().json.id
}}];

